// 일별 집계 통계 계산 및 metrics_json 생성
const item = $input.first().json;

const dayBucket = new Date();
dayBucket.setDate(dayBucket.getDate() - 1);
dayBucket.setHours(0, 0, 0, 0);
const dayBucketISO = dayBucket.toISOString();

const metricsJson = {
  hour_count:    item.hour_count || 0,
  anomaly_hours: item.anomaly_hours || 0,
  worst_severity: item.worst_severity || 'normal'
};

if (item.cpu_avg !== null) metricsJson.cpu_avg = Math.round(item.cpu_avg * 100) / 100;
if (item.mem_avg !== null) metricsJson.mem_avg = Math.round(item.mem_avg * 100) / 100;

const dominantSeverity = item.worst_severity || 'normal';

return [{
  json: {
    ...item,
    day_bucket_iso: dayBucketISO,
    metrics_json: JSON.stringify(metricsJson),
    dominant_severity: dominantSeverity
  }
}];

// Qdrant 저장용 요약 텍스트 생성
const item = $('일별 집계 계산').first().json;
const savedRow = $input.first().json;

const metricsObj = JSON.parse(item.metrics_json || '{}');
const summaryText = [
  `시스템:${item.system_name} 날짜:${item.day_bucket_iso.split('T')[0]}`,
  `수집기:${item.collector_type}/${item.metric_group}`,
  `집계시간:${metricsObj.hour_count}h 이상:${metricsObj.anomaly_hours}h`,
  item.predictions ? `예측:${item.predictions.substring(0, 200)}` : ''
].filter(Boolean).join(' | ');

return [{
  json: {
    ...item,
    summary_text: summaryText,
    pg_row_id: savedRow.id
  }
}];
